  termsTokenGuarantees: { EN: "No Guarantees", ES: "Sin Garantías", FR: "Aucune Garantie", DE: "Keine Garantien", RU: "Отсутствие гарантий", ZH: "无保证", JA: "保証なし", PT: "Sem Garantias", AR: "لا ضمانات", IT: "Nessuna Garanzia" },
